import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import PanelCliente from './components/PanelCliente';
import GestionOfertas from './components/GestionOfertas';

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(() => !!localStorage.getItem('token-falso'));
  const [userRole, setUserRole] = useState(() => localStorage.getItem('user-role')); 

  const cerrarSesion = () => {
    localStorage.clear();
    setIsLoggedIn(false);
    setUserRole(null);
    window.location.href = '/'; 
  };

  return (
    <Router>
      {/* Pasamos los estados al Header para los botones de la derecha */}
      <Header isLoggedIn={isLoggedIn} userRole={userRole} cerrarSesion={cerrarSesion} />
      <main style={{ minHeight: 'calc(100vh - 75px)' }}>
        <Routes>
          {/* El HOME siempre es accesible para todos */}
          <Route path="/" element={<Home isLoggedIn={isLoggedIn} userRole={userRole} />} />

          <Route path="/login" element={
            isLoggedIn 
              ? (userRole === 'vendedor' ? <Navigate to="/dashboard" replace /> : <Navigate to="/panel-cliente" replace />) 
              : <Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} />
          } />

          {/* Rutas Protegidas */}
          <Route path="/dashboard" element={isLoggedIn && userRole === 'vendedor' ? <Dashboard /> : <Navigate to="/login" replace />} />
          <Route path="/panel-cliente" element={isLoggedIn && userRole === 'cliente' ? <PanelCliente /> : <Navigate to="/login" replace />} />
          <Route path="/ofertas/:id" element={isLoggedIn && userRole === 'vendedor' ? <GestionOfertas /> : <Navigate to="/login" replace />} />

          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </main>
    </Router>
  );
}

export default App;
